// Código CORRIGIDO para o nó "Extrair Dados do Cliente"
const inputData = $input.first().json;

// Extrair dados crus
let assunto = inputData.assunto || inputData.body?.assunto || 'Sem assunto';
let mensagem = inputData.mensagem || inputData.body?.mensagem || inputData.conteudo || '';
let clienteNome = inputData.cliente?.nome || inputData.nome || inputData.body?.cliente?.nome || '';
let clienteEmail = inputData.cliente?.email || inputData.email || inputData.body?.cliente?.email || '';
let clienteTelefone = inputData.cliente?.telefone || inputData.telefone || inputData.body?.cliente?.telefone || '';
let clienteEmpresa = inputData.cliente?.empresa || inputData.empresa || inputData.body?.cliente?.empresa || '';
let clienteCargo = inputData.cliente?.cargo || inputData.cargo || inputData.body?.cliente?.cargo || '';
let clienteDocumento = inputData.cliente?.documento || inputData.documento || inputData.body?.cliente?.documento || '';
let clienteDepartamento = inputData.cliente?.departamento || inputData.departamento || inputData.body?.cliente?.departamento || '';
let origem = inputData.origem || inputData.body?.origem || 'desconhecido';

// 🔥 CORREÇÃO: Priorizar departamento para portal do cliente
let setorChamado;

if (origem === 'portal_cliente') {
  // Portal do Cliente: usa o departamento selecionado pelo cliente
  setorChamado = inputData.departamento || 
                 inputData.body?.departamento || 
                 clienteDepartamento || 
                 'Geral';
  console.log('🏷️ Portal Cliente - Departamento selecionado:', setorChamado);
} else {
  // Admin manual: usa o setor informado
  setorChamado = inputData.setor || 
                 inputData.departamento || 
                 inputData.body?.setor || 
                 clienteDepartamento || 
                 'Geral';
}

let canal = inputData.canal || inputData.body?.canal || inputData.origem || 'desconhecido';

// Log para debug
console.log('📝 Nome recebido:', clienteNome);
console.log('🏢 Empresa recebida:', clienteEmpresa);
console.log('🏷️ Setor informado:', setorChamado);
console.log('📱 Origem:', origem);

const resultado = {
  dados_brutos: inputData,
  extraido: {
    assunto: assunto,
    mensagem: mensagem,
    cliente: {
      nome: clienteNome,
      email: clienteEmail.toLowerCase().trim(),
      telefone: clienteTelefone,
      empresa: clienteEmpresa,
      cargo: clienteCargo,
      documento: clienteDocumento,
      departamento: clienteDepartamento
    },
    setor: setorChamado,  // ← Agora com a prioridade correta
    canal: canal,
    origem: origem  // ← Adicionado para rastreamento
  },
  recebido_em: new Date().toISOString(),
  status: 'dados_extraidos'
};

return resultado;

// Pega os dados do HTTP Request (resultado da busca)
const resultadoBusca = $input.first().json;

// Pega os dados do cliente do PRIMEIRO Code
const dadosCliente = $('Extrair Dados do Cliente').first().json.extraido.cliente;

// 🔥 PEGA O departamento_id DIRETAMENTE do nó Mapear setor 🔥
const departamento_id = $('Mapear setor').first().json.departamento_id;

let precisaCriar = false;
let clienteId = null;

console.log('RESULTADO BUSCA:', JSON.stringify(resultadoBusca));
console.log('🔴 DECIDIR - departamento_id do Mapear setor:', departamento_id);

// Verifica se encontrou cliente
if (resultadoBusca && Array.isArray(resultadoBusca) && resultadoBusca.length > 0) {
  clienteId = resultadoBusca[0].id;
  precisaCriar = false;
  console.log('✅ Cliente encontrado! ID:', clienteId);
} else if (resultadoBusca && !Array.isArray(resultadoBusca) && resultadoBusca.id) {
  clienteId = resultadoBusca.id;
  precisaCriar = false;
  console.log('✅ Cliente encontrado! ID:', clienteId);
} else {
  precisaCriar = true;
  console.log('❌ Cliente NÃO encontrado. Vai criar:', dadosCliente.email);
}

return {
  precisaCriar: precisaCriar,
  clienteId: clienteId,
  dadosCliente: dadosCliente,
  departamento_id: departamento_id  // ← VEM DO MAPEADOR!
};

// Pega os dados do chamado
const dadosCliente = $('Extrair Dados do Cliente').first().json.extraido;
const mensagem = dadosCliente.mensagem.toLowerCase();
const assunto = dadosCliente.assunto.toLowerCase();
const textoCompleto = mensagem + " " + assunto;

// INICIALIZA as variáveis
let prioridade_id = 1; // baixa padrão
let motivo = "Classificação padrão (média prioridade)";
let palavrasEncontradas = [];

// ============================================
// INFORMAÇÕES DE HORÁRIO (apenas para registro)
// ============================================
const hora = new Date().getHours();
const diaSemana = new Date().getDay();
const isHorarioComercial = (hora >= 8 && hora <= 18);
const isFimDeSemana = (diaSemana === 0 || diaSemana === 6);

if (!isHorarioComercial) {
  console.log(`📅 Chamado recebido fora do horário comercial (${hora}h)`);
  palavrasEncontradas.push('fora-horario');
}

if (isFimDeSemana) {
  console.log(`📅 Chamado recebido em fim de semana`);
  palavrasEncontradas.push('fim-de-semana');
}

// ============================================
// CRÍTICA (4) - Sistemas parados, emergências
// ============================================
const palavrasCriticas = [
  'sem energia', 'falta energia', 'energia caiu', 'luz apagou', 'no-break',
  'sem internet', 'internet caiu', 'rede caiu', 'wifi fora', 'conexão falhou',
  'servidor caiu', 'servidor fora', 'servidor parado', 'data center',
  'sistema fora', 'sistema parado', 'fora do ar', 'não funciona', 'tudo parado',
  'produção parada', 'fábrica parada', 'linha parada', 'site fora', 'app fora',
  'emergência', 'crítico', 'urgentíssimo', 'desesperador',
  'invasão', 'hackeado', 'vazamento de dados', 'ransomware', 'vírus',
  'dados perdidos', 'backup falhou', 'arquivo corrompido',
  'disco queimou', 'fonte queimou', 'incêndio', 'enchente', 'curto-circuito'
];

for (const palavra of palavrasCriticas) {
  if (textoCompleto.includes(palavra)) {
    prioridade_id = 4;
    motivo = "CRÍTICA: Sistema inoperante ou emergência detectada";
    palavrasEncontradas.push(palavra);
    break;
  }
}

// ============================================
// ALTA (3) - Urgente, mas não crítico
// ============================================
if (prioridade_id === 2) {
  const palavrasAlta = [
    'urgente', 'asap', 'rápido', 'quanto antes', 'imediatamente', 'com urgência',
    'não consigo trabalhar', 'improdutivo', 'parado parcialmente',
    'atrasado', 'prazo', 'deadline', 'vencimento', 'prejuízo', 'multa',
    'cliente insatisfeito', 'reclamação', 'nervoso',
    'bug', 'erro', 'falha', 'inconsistência', 'tela azul', 'crash', 'travou',
    'lentidão', 'demora', 'não carrega', 'não abre', 'não salva',
    'não consigo logar', 'login falhou', 'senha não funciona',
    'pagamento não processado', 'boleto não gerou', 'transação falhou'
  ];

  for (const palavra of palavrasAlta) {
    if (textoCompleto.includes(palavra)) {
      prioridade_id = 3;
      motivo = "ALTA: Urgência ou impacto significativo";
      palavrasEncontradas.push(palavra);
      break;
    }
  }
}

// ============================================
// BAIXA (1) - Dúvidas, orientações
// ============================================
if (prioridade_id === 2) {
  const palavrasBaixa = [
    'dúvida', 'como faço', 'como posso', 'como eu', 'qual é',
    'ajuda', 'orientação', 'instrução', 'explicação', 'me ensina',
    'tutorial', 'documentação', 'manual', 'passo a passo', 'guia',
    'sugestão', 'melhoria', 'nova funcionalidade', 'ideia',
    'consulta', 'verificar', 'confirmar', 'validar', 'agradecimento', 'obrigado'
  ];

  for (const palavra of palavrasBaixa) {
    if (textoCompleto.includes(palavra)) {
      prioridade_id = 1;
      motivo = "BAIXA: Dúvida ou solicitação de informação";
      palavrasEncontradas.push(palavra);
      break;
    }
  }
}

// ============================================
// REGRAS ESPECIAIS
// ============================================

// Financeiro sobe prioridade
const palavrasFinanceiro = ['pagamento', 'boleto', 'fatura', 'nota fiscal', 'reembolso'];
for (const palavra of palavrasFinanceiro) {
  if (textoCompleto.includes(palavra) && prioridade_id < 3) {
    prioridade_id = 3;
    motivo += " + Assunto financeiro";
    palavrasEncontradas.push(palavra + '(financeiro)');
    break;
  }
}

// ============================================
// LOG PARA DEBUG
// ============================================
console.log('=' .repeat(50));
console.log('CLASSIFICAÇÃO DE PRIORIDADE:');
console.log(`Horário comercial: ${isHorarioComercial ? 'Sim' : 'Não'} (${hora}h)`);
console.log(`Fim de semana: ${isFimDeSemana ? 'Sim' : 'Não'}`);
console.log(`Prioridade: ${prioridade_id}`);
console.log(`Motivo: ${motivo}`);
console.log(`Palavras: ${palavrasEncontradas.join(', ')}`);
console.log('=' .repeat(50));

// ============================================
// PREPARA DADOS PARA SAÍDA
// ============================================
const inputData = $input.first().json;

// Preserva o clienteId vindo do Merge
const clienteId = inputData.clienteId || null;

// 🔥 PRESERVA O departamento_id que veio do Mapear setor 🔥
const departamento_id = inputData.departamento_id || 7;

console.log(`🔴 CLASSIFICAR - departamento_id recebido: ${inputData.departamento_id}`);
console.log(`🔴 CLASSIFICAR - departamento_id final: ${departamento_id}`);

return {
  clienteId: clienteId,
  prioridade_id: prioridade_id,
  prioridade_motivo: motivo,
  palavras_chave: palavrasEncontradas,
  assunto: dadosCliente.assunto,
  mensagem_original: dadosCliente.mensagem,
  canal: dadosCliente.canal,
  dadosCliente: dadosCliente.cliente,
  metadata_horario: {
    hora: hora,
    horario_comercial: isHorarioComercial,
    fim_de_semana: isFimDeSemana
  },
  departamento_id: departamento_id  // ← LINHA ADICIONADA!
};

const data = $input.first().json;

// No ramo TRUE, o cliente acabou de ser criado
const clienteId = data[0]?.id || data.id;

// 🔥 DEPARTAMENTO_ID VEM DO Decidir se Cria Cliente (via Criar Cliente) 🔥
const departamento_id = data.departamento_id;

console.log('Ramo TRUE - Cliente ID:', clienteId);
console.log('Ramo TRUE - departamento_id:', departamento_id);

return {
  clienteId: clienteId,
  dadosCliente: {
    nome: data.nome,
    email: data.email,
    telefone: data.telefone
  },
  departamento_id: departamento_id
};

const data = $input.first().json;

// 🔥 DEPARTAMENTO_ID VEM DO Decidir se Cria Cliente 🔥
const departamento_id = data.departamento_id;

console.log('Ramo FALSE - clienteId:', data.clienteId);
console.log('Ramo FALSE - departamento_id:', departamento_id);

let clienteId = data.clienteId;

return {
  clienteId: clienteId,
  dadosCliente: data.dadosCliente,
  departamento_id: departamento_id
};

const inputData = $input.first().json;

console.log('=' .repeat(50));
console.log('FORÇAR CLIENTE ID - DADOS RECEBIDOS:');
console.log(JSON.stringify(inputData, null, 2));
console.log('=' .repeat(50));

let clienteId = inputData.clienteId;

if (!clienteId && inputData.dadosCliente && inputData.dadosCliente.id) {
  clienteId = inputData.dadosCliente.id;
}

console.log('Cliente ID final:', clienteId);
console.log('Departamento ID recebido:', inputData.departamento_id);

if (!clienteId) {
  throw new Error('clienteId não encontrado. Dados: ' + JSON.stringify(inputData));
}

// 🔥 NOVO: Mapear canal para ID
const canalMap = {
  'whatsapp': 1,
  'email': 2,
  'teams': 3,
  'formulário': 4,
  'formulario': 4,
  'telefone': 5,
  'desconhecido': 1  // padrão WhatsApp
};

// Pega o canal do inputData (vem do nó Extrair Dados do Cliente)
let canalNome = (inputData.canal || 'whatsapp').toLowerCase().trim();
// Remove acentos para mapeamento
canalNome = canalNome.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const canalId = canalMap[canalNome] || 1;

console.log(`📞 Canal identificado: "${inputData.canal}" → ID: ${canalId}`);

// 🔥 USAR o departamento_id que veio do Mapear setor
const departamento_id = inputData.departamento_id || 7;

console.log(`✅ Departamento ID final: ${departamento_id}`);

return {
  cliente_id: clienteId,
  canal_id: canalId,  // ← AGORA DINÂMICO!
  assunto: inputData.assunto,
  mensagem_original: inputData.mensagem_original,
  prioridade_id: inputData.prioridade_id || 2,
  status: "Novo",
  departamento_id: departamento_id
};

// Nó "Mapear setor" - Versão CORRIGIDA com suporte a ID direto e melhor debug
const inputData = $input.first().json;

console.log('=' .repeat(50));
console.log('🏷️ MAPEAMENTO DE SETOR');
console.log('=' .repeat(50));

// 🔥 NOVO: Se já veio como número (ID do departamento), usa direto
if (inputData.departamento_id && typeof inputData.departamento_id === 'number' && inputData.departamento_id >= 1 && inputData.departamento_id <= 7) {
  const deptoMapIdToName = {
    1: 'Financeiro', 2: 'RH', 3: 'TI', 4: 'Suprimentos',
    5: 'Administrativo', 6: 'Jurídico', 7: 'Geral'
  };
  const nomeSetor = deptoMapIdToName[inputData.departamento_id];
  console.log(`✅ Já veio com departamento_id: ${inputData.departamento_id} → ${nomeSetor}`);

  return {
    ...inputData,
    departamento_id: inputData.departamento_id,
    nome_setor_original: nomeSetor,
    setor_normalizado: nomeSetor.toLowerCase(),
    mapeado_em: new Date().toISOString(),
    veio_como_id: true
  };
}

// Pega o setor de diferentes lugares possíveis
let setor = inputData.extraido?.setor || 
           inputData.setor || 
           inputData.extraido?.cliente?.departamento || 
           inputData.departamento ||
           'Geral';

console.log('Setor ORIGINAL:', JSON.stringify(setor));
console.log('Origem do chamado:', inputData.extraido?.origem || inputData.origem || 'desconhecido');
console.log('Tipo:', typeof setor);

// Garantir que setor é string
if (!setor || typeof setor !== 'string') {
  setor = 'Geral';
  console.log('⚠️ Setor inválido, usando padrão: Geral');
}

// Converter para minúsculo e limpar
const setorLower = setor.toLowerCase().trim();
console.log(`Setor normalizado: "${setorLower}"`);

// Mapeamento direto
let departamento_id = null;

if (setorLower === 'financeiro' || setorLower === 'finanças' || setorLower === 'financas') {
  departamento_id = 1;
  console.log('🎯 Financeiro → ID 1');
}
else if (setorLower === 'rh' || setorLower === 'recursos humanos' || setorLower === 'hr') {
  departamento_id = 2;
  console.log('🎯 RH → ID 2');
}
else if (setorLower === 'ti' || setorLower === 'tecnologia' || setorLower === 'informática' || setorLower === 'informatica' || setorLower === 'it') {
  departamento_id = 3;
  console.log('🎯 TI → ID 3');
}
else if (setorLower === 'suprimentos' || setorLower === 'suprimentos' || setorLower === 'compras' || setorLower === 'logística' || setorLower === 'logistica' || setorLower === 'supply') {
  departamento_id = 4;
  console.log('🎯 Suprimentos → ID 4');
}
else if (setorLower === 'administrativo' || setorLower === 'adm' || setorLower === 'admin' || setorLower === 'administracao') {
  departamento_id = 5;
  console.log('🎯 Administrativo → ID 5');
}
else if (setorLower === 'jurídico' || setorLower === 'juridico' || setorLower === 'legal') {
  departamento_id = 6;
  console.log('🎯 Jurídico → ID 6');
}
else if (setorLower === 'geral' || setorLower === 'general' || setorLower === '') {
  departamento_id = 7;
  console.log('🎯 Geral → ID 7');
}
else {
  // Busca parcial para palavras próximas
  if (setorLower.includes('suprimento') || setorLower.includes('compras') || setorLower.includes('logist')) {
    departamento_id = 4;
    console.log('🎯 Suprimentos (parcial) → ID 4');
  }
  else if (setorLower.includes('finance') || setorLower.includes('financ')) {
    departamento_id = 1;
    console.log('🎯 Financeiro (parcial) → ID 1');
  }
  else if (setorLower.includes('tecno') || setorLower.includes('inform')) {
    departamento_id = 3;
    console.log('🎯 TI (parcial) → ID 3');
  }
  else if (setorLower.includes('admin')) {
    departamento_id = 5;
    console.log('🎯 Administrativo (parcial) → ID 5');
  }
  else if (setorLower.includes('jurid')) {
    departamento_id = 6;
    console.log('🎯 Jurídico (parcial) → ID 6');
  }
  else if (setorLower.includes('rh') || setorLower.includes('recurs')) {
    departamento_id = 2;
    console.log('🎯 RH (parcial) → ID 2');
  }
  else {
    departamento_id = 7;
    console.log(`⚠️ Setor "${setor}" não reconhecido, usando Geral (ID 7)`);
  }
}

console.log('=' .repeat(50));
console.log(`✅ RESULTADO: "${setor}" → departamento_id: ${departamento_id}`);
console.log('=' .repeat(50));

// Retornar os dados atualizados
return {
  ...inputData,
  departamento_id: departamento_id,
  nome_setor_original: setor,
  setor_normalizado: setorLower,
  mapeado_em: new Date().toISOString(),
  veio_como_id: false
};

const authResp = $input.first().json;
const dadosCliente = $('Decidir se Cria Cliente').first().json;

// Supabase signUp retorna { id, email, ... } em caso de sucesso
// ou { msg: 'User already registered' } se já existe
let authClienteId = authResp?.id || authResp?.user?.id || null;

if (!authClienteId && authResp?.msg?.toLowerCase().includes('already registered')) {
  console.log('⚠️ Auth: cliente já registrado, prosseguindo sem ID do Auth');
} else if (authClienteId) {
  console.log('✅ Auth criado para cliente:', authClienteId);
} else {
  console.log('⚠️ Auth: resposta inesperada:', JSON.stringify(authResp));
}

return {
  ...dadosCliente,
  auth_cliente_id: authClienteId
};
